// n8n hands the Error Trigger a payload shaped roughly like:
// { execution: { id, url, mode, error: { message, stack, node } }, workflow: { id, name } }
// Extract defensively - the exact shape has shifted across n8n versions,
// so don't assume every field is present.
const j = $json;

const workflowName = j.workflow?.name || 'Unknown workflow';
const failedNode = j.execution?.error?.node?.name || j.execution?.lastNodeExecuted || 'Unknown node';
const errorMessage = j.execution?.error?.message || j.execution?.error?.description || 'No error message captured';
const executionUrl = j.execution?.url || '';
const executionMode = j.execution?.mode || 'unknown';

return {
  json: {
    timestamp: new Date().toISOString(),
    workflowName,
    failedNode,
    errorMessage,
    executionUrl,
    executionMode
  }
};

parameters.text:
=🚨 CASTING PIPELINE ERROR

*Workflow:* {{ $json.workflowName }}
*Failed at:* {{ $json.failedNode }}
*Error:* {{ $json.errorMessage }}
*Mode:* {{ $json.executionMode }}

{{ $json.executionUrl ? 'View: ' + $json.executionUrl : '' }}

This is a system failure, not a routine applicant rejection - something actually broke.
